  "active",
  "funded",
  "closed",
  "cancelled"
]);
var portfolioStatusEnum = pgEnum("portfolio_status", [
  "active",
  "completed",
  "pending",
  "cancelled"
]);
var transactionTypeEnum = pgEnum("transaction_type", [
  "investment",
  "dividend",
