async function fetchFeed({ pageParam, room }: { pageParam?: string; room?: string }): Promise<FeedResponse> {
  const baseUrl = getApiUrl();
  const url = new URL("/api/watch/feed", baseUrl);

  if (pageParam) {
    url.searchParams.set("cursor", pageParam);
  }
  if (room) {
    url.searchParams.set("room", room);
  }

  const res = await fetch(url, { credentials: "include" });
  if (!res.ok) {
    throw new Error("Failed to fetch feed");
  }
  return res.json();
}

