struct RoomFilterView: View {
    @Binding var selectedRoom: RoomCategory?
    let onSelect: (RoomCategory?) -> Void
    @Environment(\.dismiss) private var dismiss

    var body: some View {
        NavigationStack {
            List {
                Button(action: {
                    onSelect(nil)
                    dismiss()
                }) {
                    HStack {
                        Text("All Rooms")
                            .font(.system(size: 14))
                        Spacer()
                        if selectedRoom == nil {
                            Image(systemName: "checkmark")
                                .foregroundColor(.medicalBlue)
                        }
                    }
                }

                ForEach(RoomCategory.allCases, id: \.self) { room in
                    Button(action: {
                        onSelect(room)
                        dismiss()
                    }) {
                        HStack(spacing: 8) {
                            Circle()
                                .fill(room.color)
                                .frame(width: 10, height: 10)

                            Text(room.displayName)
                                .font(.system(size: 14))

                            Spacer()

                            if selectedRoom == room {
                                Image(systemName: "checkmark")
                                    .foregroundColor(.medicalBlue)
                            }
                        }
                    }
                }
            }
            .navigationTitle("Filter")
            .navigationBarTitleDisplayMode(.inline)
        }
    }
}
