","path":null,"size_bytes":436,"size_tokens":null},"watch-app/MedInvestWatch/Services/APIClient.swift":{"content":"import Foundation

actor APIClient {
    static let shared = APIClient()

    // IMPORTANT: Replace with your deployed MedInvest Replit URL
    // Development: "https://YOUR-REPL-NAME.replit.dev"
    // Production: "https://your-production-domain.com"
    private let baseURL: String = {
        #if DEBUG
        return "https://YOUR-REPL-NAME.replit.dev"
        #else
        return "https://your-production-domain.com"
        #endif
    }()

    private var authToken: String?

    func setAuthToken(_ token: String) {
        self.authToken = token
    }

    // MARK: - Feed Endpoints

    func getFeed(cursor: String? = nil, room: String? = nil) async throws -> FeedResponse {
        var urlComponents = URLComponents(string: "\(baseURL)/api/watch/feed")!
        var queryItems: [URLQueryItem] = []

        if let cursor = cursor {
            queryItems.append(URLQueryItem(name: "cursor", value: cursor))
        }
        if let room = room {
            queryItems.append(URLQueryItem(name: "room", value: room))
        }

        urlComponents.queryItems = queryItems.isEmpty ? nil : queryItems

        return try await request(url: urlComponents.url!)
    }

    func getPost(id: Int) async throws -> Post {
        let url = URL(string: "\(baseURL)/api/watch/posts/\(id)")!
        return try await request(url: url)
    }

    func getComments(postId: Int) async throws -> CommentsResponse {
        let url = URL(string: "\(baseURL)/api/watch/posts/\(postId)/comments")!
        return try await request(url: url)
    }

    func getTrending() async throws -> TrendingResponse {
        let url = URL(string: "\(baseURL)/api/watch/trending")!
        return try await request(url: url)
    }

    func getNotifications() async throws -> WatchNotificationsResponse {
        let url = URL(string: "\(baseURL)/api/watch/notifications")!
        return try await request(url: url)
    }

    func getRooms() async throws -> RoomsResponse {
        let url = URL(string: "\(baseURL)/api/watch/rooms")!
        return try await request(url: url)
    }

    // MARK: - Actions

    func vote(postId: Int, direction: VoteDirection) async throws {
        let url = URL(string: "\(baseURL)/api/watch/posts/\(postId)/vote")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try JSONEncoder().encode(["direction": direction.rawValue])

        try await performRequest(request)
    }

    func bookmark(postId: Int, add: Bool) async throws {
        let url = URL(string: "\(baseURL)/api/watch/posts/\(postId)/bookmark")!
        var request = URLRequest(url: url)
        request.httpMethod = add ? "POST" : "DELETE"

        try await performRequest(request)
    }

    // MARK: - Sync Status

    func getSyncStatus() async throws -> SyncStatus {
        let url = URL(string: "\(baseURL)/api/watch/sync/status")!
        return try await request(url: url)
    }

    // MARK: - Private Helpers

    private func request<T: Decodable>(url: URL) async throws -> T {
        var request = URLRequest(url: url)
        request.setValue("application/json", forHTTPHeaderField: "Accept")

        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse,
              200..<300 ~= httpResponse.statusCode else {
            throw APIError.invalidResponse
        }

        let decoder = JSONDecoder()
        return try decoder.decode(T.self, from: data)
    }

    private func performRequest(_ request: URLRequest) async throws {
        var mutableRequest = request

        if let token = authToken {
            mutableRequest.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let (_, response) = try await URLSession.shared.data(for: mutableRequest)

        guard let httpResponse = response as? HTTPURLResponse,
              200..<300 ~= httpResponse.statusCode else {
            throw APIError.invalidResponse
        }
    }
}

enum APIError: LocalizedError {
    case invalidResponse
    case unauthorized
    case networkError

    var errorDescription: String? {
        switch self {
        case .invalidResponse: return "Invalid response from server"
        case .unauthorized: return "Authentication required"
        case .networkError: return "Network connection error"
        }
    }
}
