    let post: Post
    @State private var isPulsing = false

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(spacing: 6) {
                Text(post.room.name)
                    .font(.system(size: 9, weight: .medium))
                    .padding(.horizontal, 6)
                    .padding(.vertical, 2)
                    .background(post.room.swiftUIColor.opacity(0.3))
                    .foregroundColor(post.room.swiftUIColor)
                    .cornerRadius(4)

                Spacer()

                Text(post.timeAgo)
                    .font(.system(size: 9))
                    .foregroundColor(.textSecondary)
            }

            Text(post.content)
                .font(.system(size: 13))
                .lineLimit(2)
                .foregroundColor(.white)

            HStack(spacing: 8) {
                HStack(spacing: 4) {
                    if post.author.isVerified {
                        Image(systemName: "checkmark.seal.fill")
                            .font(.system(size: 8))
                            .foregroundColor(.medicalBlue)
                    }
                    Text(post.displayName)
                        .font(.system(size: 10))
                        .foregroundColor(.textSecondary)
                        .lineLimit(1)
                }

                Spacer()

                HStack(spacing: 4) {
                    Image(systemName: post.score >= 0 ? "arrow.up" : "arrow.down")
                        .font(.system(size: 9, weight: .bold))
                        .foregroundColor(scoreColor)

                    Text("\(abs(post.score))")
                        .font(.system(size: 10, weight: .semibold))
                        .foregroundColor(scoreColor)
                }
                .padding(.horizontal, 6)
                .padding(.vertical, 3)
                .background(
                    RoundedRectangle(cornerRadius: 6)
                        .fill(scoreColor.opacity(isPulsing ? 0.2 : 0.1))
                )
                .animation(.easeInOut(duration: 1.5).repeatForever(autoreverses: true), value: isPulsing)

                HStack(spacing: 2) {
                    Image(systemName: "bubble.right")
                        .font(.system(size: 9))
                    Text("\(post.commentsCount)")
                        .font(.system(size: 10))
                }
                .foregroundColor(.textSecondary)
            }
        }
        .padding(10)
        .background(Color.surfaceGray)
        .cornerRadius(12)
        .onAppear { isPulsing = true }
    }

    private var scoreColor: Color {
        if post.score > 10 { return .vitalityGreen }
        if post.score < -5 { return .alertRed }
        return .textSecondary
    }
}
