import { View, StyleSheet, Pressable } from "react-native";
import { Feather } from "@expo/vector-icons";
import Animated, {
  useAnimatedStyle,
  useSharedValue,
  withSpring,
  WithSpringConfig,
} from "react-native-reanimated";
import * as Haptics from "expo-haptics";

import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import { Spacing, BorderRadius } from "@/constants/theme";
import { Post, VoteDirection } from "@/types/post";

interface PostCardProps {
  post: Post;
  onVote: (postId: number, direction: VoteDirection) => void;
  onBookmark: (postId: number, isBookmarked: boolean) => void;
  onPress?: () => void;
}

const springConfig: WithSpringConfig = {
  damping: 15,
  mass: 0.3,
  stiffness: 150,
  overshootClamping: true,
};

const AnimatedPressable = Animated.createAnimatedComponent(Pressable);

const MedicalColors = {
  primary: "#00A3E0",
  success: "#4CAF50",
  alert: "#FF6B6B",
  surface: "#1C1C1E",
  surfaceVariant: "#2C2C2E",
  textSecondary: "#8E8E93",
};

function formatTimeAgo(dateString: string): string {
  const date = new Date(dateString);
  const now = new Date();
  const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

  if (seconds < 60) return "now";
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)}d`;
  return `${Math.floor(seconds / 604800)}w`;
}

export function PostCard({ post, onVote, onBookmark, onPress }: PostCardProps) {
  const { theme, isDark } = useTheme();
  const scale = useSharedValue(1);

  const displayName = post.is_anonymous
    ? post.anonymous_name || "Anonymous"
    : post.author.full_name;

  const score = post.upvotes - post.downvotes;

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
  }));

  const handlePressIn = () => {
    scale.value = withSpring(0.98, springConfig);
  };

  const handlePressOut = () => {
    scale.value = withSpring(1, springConfig);
  };

  const handleUpvote = () => {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    const newDirection: VoteDirection = post.user_vote === "up" ? null : "up";
    onVote(post.id, newDirection);
  };

  const handleDownvote = () => {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    const newDirection: VoteDirection =
      post.user_vote === "down" ? null : "down";
    onVote(post.id, newDirection);
  };

  const handleBookmark = () => {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    onBookmark(post.id, !post.is_bookmarked);
  };

  const backgroundColor = isDark
    ? MedicalColors.surface
    : theme.backgroundDefault;

  return (
    <AnimatedPressable
      style={[styles.container, { backgroundColor }, animatedStyle]}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      onPress={onPress}
      testID={`post-card-${post.id}`}
    >
      <View style={styles.header}>
        <View
          style={[styles.roomBadge, { backgroundColor: post.room.color + "20" }]}
        >
          <ThemedText style={[styles.roomIcon]}>{post.room.icon}</ThemedText>
          <ThemedText
            style={[styles.roomName, { color: post.room.color }]}
            type="small"
          >
            {post.room.name}
          </ThemedText>
        </View>
        <ThemedText
          style={[styles.timestamp, { color: MedicalColors.textSecondary }]}
          type="small"
        >
          {formatTimeAgo(post.created_at)}
        </ThemedText>
      </View>

      <View style={styles.authorRow}>
        <View style={styles.avatar}>
          <ThemedText style={styles.avatarText}>
            {displayName.charAt(0).toUpperCase()}
          </ThemedText>
        </View>
        <View style={styles.authorInfo}>
          <View style={styles.nameRow}>
            <ThemedText style={styles.authorName} type="body">
              {displayName}
            </ThemedText>
            {post.author.is_verified && !post.is_anonymous ? (
              <Feather
                name="check-circle"
                size={14}
                color={MedicalColors.primary}
                style={styles.verifiedIcon}
              />
            ) : null}
          </View>
          {!post.is_anonymous && post.author.specialty ? (
            <ThemedText
              style={[styles.specialty, { color: MedicalColors.textSecondary }]}
              type="small"
            >
              {post.author.specialty}
            </ThemedText>
          ) : null}
        </View>
      </View>

      <ThemedText style={styles.content} type="body">
        {post.content}
      </ThemedText>

      {post.hashtags.length > 0 ? (
        <View style={styles.hashtagsRow}>
          {post.hashtags.slice(0, 3).map((tag, index) => (
            <ThemedText
              key={index}
              style={[styles.hashtag, { color: MedicalColors.primary }]}
              type="small"
            >
              {tag}
            </ThemedText>
          ))}
        </View>
      ) : null}

      <View style={styles.actionsRow}>
        <View style={styles.voteContainer}>
          <Pressable
            style={[
              styles.voteButton,
              post.user_vote === "up" && styles.voteButtonActive,
            ]}
            onPress={handleUpvote}
            testID={`upvote-button-${post.id}`}
          >
            <Feather
              name="arrow-up"
              size={18}
              color={
                post.user_vote === "up"
                  ? MedicalColors.success
                  : MedicalColors.textSecondary
              }
            />
          </Pressable>

          <ThemedText
            style={[
              styles.scoreText,
              {
                color:
                  post.user_vote === "up"
                    ? MedicalColors.success
                    : post.user_vote === "down"
                      ? MedicalColors.alert
                      : theme.text,
              },
            ]}
          >
            {score}
          </ThemedText>

          <Pressable
            style={[
              styles.voteButton,
              post.user_vote === "down" && styles.voteButtonActive,
            ]}
            onPress={handleDownvote}
            testID={`downvote-button-${post.id}`}
          >
            <Feather
              name="arrow-down"
              size={18}
              color={
                post.user_vote === "down"
                  ? MedicalColors.alert
                  : MedicalColors.textSecondary
              }
            />
          </Pressable>
        </View>

        <Pressable style={styles.actionButton} testID={`comments-button-${post.id}`}>
          <Feather
            name="message-circle"
            size={18}
            color={MedicalColors.textSecondary}
          />
          <ThemedText
            style={[styles.actionText, { color: MedicalColors.textSecondary }]}
            type="small"
          >
            {post.comments_count}
          </ThemedText>
        </Pressable>

        <Pressable
          style={styles.actionButton}
          onPress={handleBookmark}
          testID={`bookmark-button-${post.id}`}
        >
          <Feather
            name={post.is_bookmarked ? "bookmark" : "bookmark"}
            size={18}
            color={
              post.is_bookmarked
                ? MedicalColors.primary
                : MedicalColors.textSecondary
            }
            style={post.is_bookmarked ? { opacity: 1 } : { opacity: 0.7 }}
          />
        </Pressable>
      </View>
    </AnimatedPressable>
  );
}

const styles = StyleSheet.create({
