import { useHeaderHeight } from "@react-navigation/elements";
import { useBottomTabBarHeight } from "@react-navigation/bottom-tabs";
import { useQuery } from "@tanstack/react-query";
import { Feather } from "@expo/vector-icons";
import * as Haptics from "expo-haptics";

import { useTheme } from "@/hooks/useTheme";
import { Spacing, BorderRadius } from "@/constants/theme";
import { ThemedText } from "@/components/ThemedText";
import { Notification, NotificationsResponse } from "@/types/notification";

const MedicalColors = {
  primary: "#00A3E0",
  success: "#4CAF50",
  alert: "#FF6B6B",
  surface: "#1C1C1E",
  textSecondary: "#8E8E93",
};

function formatTimeAgo(dateString: string): string {
  const date = new Date(dateString);
  const now = new Date();
  const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

  if (seconds < 60) return "now";
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)}d ago`;
  return `${Math.floor(seconds / 604800)}w ago`;
}

function getNotificationIcon(type: Notification['type']): keyof typeof Feather.glyphMap {
  switch (type) {
    case 'vote': return 'arrow-up';
    case 'comment': return 'message-circle';
    case 'mention': return 'at-sign';
    case 'follow': return 'user-plus';
    case 'bookmark': return 'bookmark';
    default: return 'bell';
  }
}

function getNotificationColor(type: Notification['type']): string {
  switch (type) {
    case 'vote': return MedicalColors.success;
    case 'comment': return MedicalColors.primary;
    case 'mention': return '#9B59B6';
    case 'follow': return MedicalColors.primary;
    case 'bookmark': return '#F39C12';
    default: return MedicalColors.textSecondary;
  }
}

export default function NotificationsScreen() {
  const headerHeight = useHeaderHeight();
  const tabBarHeight = useBottomTabBarHeight();
  const { theme, isDark } = useTheme();

  const { data, isLoading } = useQuery<NotificationsResponse>({
    queryKey: ["/api/notifications"],
  });

  const handleNotificationPress = (notification: Notification) => {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
  };

  const renderNotification = ({ item }: { item: Notification }) => {
    const iconColor = getNotificationColor(item.type);
    const backgroundColor = isDark ? MedicalColors.surface : theme.backgroundDefault;

    return (
      <Pressable
        style={[
          styles.notificationItem,
          { backgroundColor },
          !item.is_read && styles.unreadItem,
        ]}
        onPress={() => handleNotificationPress(item)}
        testID={`notification-${item.id}`}
      >
        <View style={[styles.iconContainer, { backgroundColor: iconColor + '20' }]}>
          <Feather
            name={getNotificationIcon(item.type)}
            size={18}
            color={iconColor}
          />
        </View>

        <View style={styles.contentContainer}>
          <View style={styles.headerRow}>
            <ThemedText style={styles.title} numberOfLines={1}>
              {item.title}
            </ThemedText>
            <ThemedText style={[styles.timestamp, { color: MedicalColors.textSecondary }]}>
              {formatTimeAgo(item.created_at)}
