          </View>

          <ThemedText
            style={[styles.body, { color: MedicalColors.textSecondary }]}
            numberOfLines={2}
          >
            {item.body}
          </ThemedText>
        </View>

        {!item.is_read ? (
          <View style={[styles.unreadDot, { backgroundColor: MedicalColors.primary }]} />
        ) : null}
      </Pressable>
    );
  };

  const renderEmpty = () => {
    if (isLoading) {
      return (
        <View style={styles.centered}>
          <Feather name="bell" size={48} color={MedicalColors.textSecondary} />
          <ThemedText style={[styles.emptyText, { color: MedicalColors.textSecondary }]}>
            Loading notifications...
          </ThemedText>
        </View>
      );
    }

    return (
      <View style={styles.centered}>
        <Feather name="bell-off" size={48} color={MedicalColors.textSecondary} />
        <ThemedText style={styles.emptyTitle}>No notifications yet</ThemedText>
        <ThemedText style={[styles.emptyText, { color: MedicalColors.textSecondary }]}>
          When someone interacts with your posts, you'll see it here
        </ThemedText>
      </View>
    );
  };

  return (
    <FlatList
      style={{ flex: 1, backgroundColor: theme.backgroundRoot }}
      contentContainerStyle={{
        paddingTop: headerHeight + Spacing.md,
        paddingBottom: tabBarHeight + Spacing.xl,
        paddingHorizontal: Spacing.md,
        flexGrow: 1,
      }}
      data={data?.notifications || []}
      renderItem={renderNotification}
      keyExtractor={(item) => item.id.toString()}
      ListEmptyComponent={renderEmpty}
      showsVerticalScrollIndicator={false}
      testID="notifications-list"
    />
  );
}

