import WatchKit

struct PostDetailView: View {
    let post: Post
    @State private var userVote: VoteDirection?
    @State private var isBookmarked: Bool
    @State private var currentScore: Int

    init(post: Post) {
        self.post = post
        _userVote = State(initialValue: post.userVote)
        _isBookmarked = State(initialValue: post.isBookmarked)
        _currentScore = State(initialValue: post.score)
    }

    var body: some View {
        ScrollView {
            VStack(alignment: .leading, spacing: 12) {
                HStack {
                    Text(post.room.name)
                        .font(.system(size: 11, weight: .medium))
                        .padding(.horizontal, 8)
                        .padding(.vertical, 4)
                        .background(post.room.swiftUIColor.opacity(0.3))
                        .foregroundColor(post.room.swiftUIColor)
                        .cornerRadius(6)

                    Spacer()

                    Text(post.timeAgo)
                        .font(.caption2)
                        .foregroundColor(.textSecondary)
                }

                Text(post.content)
                    .font(.system(size: 14))

                HStack(spacing: 6) {
                    Circle()
                        .fill(Color.subtleGray)
                        .frame(width: 24, height: 24)
                        .overlay(
                            Text(String(post.displayName.prefix(1)))
                                .font(.system(size: 10, weight: .medium))
                        )

                    VStack(alignment: .leading, spacing: 1) {
                        HStack(spacing: 4) {
                            Text(post.displayName)
                                .font(.system(size: 11, weight: .medium))

                            if post.author.isVerified {
                                Image(systemName: "checkmark.seal.fill")
                                    .font(.system(size: 9))
                                    .foregroundColor(.medicalBlue)
                            }
                        }

                        if let specialty = post.author.specialty {
                            Text(specialty)
                                .font(.system(size: 9))
                                .foregroundColor(.textSecondary)
                        }
                    }
                }
                .padding(.vertical, 8)

                Divider()
                    .background(Color.subtleGray)

                HStack(spacing: 16) {
                    Button(action: { vote(.up) }) {
                        Image(systemName: userVote == .up ? "arrow.up.circle.fill" : "arrow.up.circle")
                            .font(.system(size: 20))
                            .foregroundColor(userVote == .up ? .vitalityGreen : .textSecondary)
                    }
                    .buttonStyle(.plain)

                    Text("\(currentScore)")
                        .font(.system(size: 14, weight: .bold))
                        .foregroundColor(scoreColor)
                        .frame(minWidth: 30)

                    Button(action: { vote(.down) }) {
                        Image(systemName: userVote == .down ? "arrow.down.circle.fill" : "arrow.down.circle")
                            .font(.system(size: 20))
                            .foregroundColor(userVote == .down ? .alertRed : .textSecondary)
                    }
                    .buttonStyle(.plain)

                    Spacer()

                    Button(action: { toggleBookmark() }) {
                        Image(systemName: isBookmarked ? "bookmark.fill" : "bookmark")
                            .font(.system(size: 18))
                            .foregroundColor(isBookmarked ? .medicalBlue : .textSecondary)
                    }
                    .buttonStyle(.plain)
                }
                .padding(.vertical, 8)

                HStack {
                    Image(systemName: "bubble.right")
                        .font(.system(size: 12))
                    Text("\(post.commentsCount) comments")
                        .font(.system(size: 12))
                    Spacer()
                    Text("Open on iPhone to view")
                        .font(.system(size: 9))
                        .foregroundColor(.textSecondary)
                }
                .foregroundColor(.textSecondary)
            }
            .padding(12)
        }
        .navigationTitle("Post")
        .navigationBarTitleDisplayMode(.inline)
    }

    private var scoreColor: Color {
        if currentScore > 10 { return .vitalityGreen }
        if currentScore < -5 { return .alertRed }
        return .white
    }

    private func vote(_ direction: VoteDirection) {
        WKInterfaceDevice.current().play(.click)

        if userVote == direction {
            currentScore -= (direction == .up ? 1 : -1)
            userVote = nil
        } else {
            if let previous = userVote {
                currentScore -= (previous == .up ? 1 : -1)
            }
            currentScore += (direction == .up ? 1 : -1)
            userVote = direction
        }

        Task {
            try? await APIClient.shared.vote(postId: post.id, direction: direction)
        }
    }

    private func toggleBookmark() {
        WKInterfaceDevice.current().play(.click)
        isBookmarked.toggle()

        Task {
            try? await APIClient.shared.bookmark(postId: post.id, add: isBookmarked)
        }
    }
}
